  ('fire-eq-tech-moex-01946', 'fire-eq-tech', 'fire-eq-tech-moex-104-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '某一場所應設置出口標示燈與避難方向指示燈，而其步行距離之有效範圍，下列何者錯誤？', '["有不易看清或識別該燈情形者，該有效範圍為10公尺", "C級出口標示燈，該有效範圍為15公尺", "A級避難方向指示燈，該有效範圍為20公尺", "B級避難方向指示燈，該有效範圍為10公尺"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "d267b2422afc", "answer_pdf_sha1": "2564ebe1eb47", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "402", "s": "0709", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
